<template>
    <section class="main-content">
       <loader :is-visible="isLoading"></loader>
           <div  id="divMainLeadData" v-cloak>
           <div class="row">
                   <div class="col-md-12 padding-t_8">
                       <div class="theme-primary partition-full">
                           <span class="p-name text-white">{{$t('ManageContact')}}</span>                           
                       </div>
                   </div>
               </div>
               <div class="border p-3">
                   <Form  ref="form">
                       <dynamic-form lang="en" ref="StageForm" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit">
                       </dynamic-form>
                       <div class="col-lg-6">
                       <div class="py-2"><small><span class="text-danger">
                                   {{ $t('MandatoryString') }}</span></small>
                       </div>
                       </div>
                   </Form>
               </div>
           </div>
       </section>        
</template>
<script>
import ContactDataService from "../../../services/DataService";
export default {
    data(){
        return{
            isLoading:false,
            contactId: this.$route.params.id,
            userId:null,
            compnayId:null,
            FormSchema:[],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success save",
                    text: "<i class='fa fa-save pr-2'></i>Submit",
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.onCancel
                }
            ]
        }
    },
    created:function(){
        this.userId= this.GetUserInfo.ID;
        this.companyId= this.GetUserInfo.CompanyId;
        this.FetchData();
    },
    methods:{
        onCancel: function () {
            this.$router.push({ name: 'ContactListing' });
        },
        FetchData:function(){
            var vm = this;
            vm.isLoading=true;
            const params = `recordId=${vm.$route.params.id}&moduleName=CRM&subModuleCode=CRM_CONTACTS&langCode=en`;
            ContactDataService.GetDynamicForm(params).then(function (response) {
                vm.isLoading=false;
                vm.FormSchema = vm.$refs.StageForm.ConvertCustomFieldIntoDynamicFormObj(response.data.data);                    
                vm.FormSchema.forEach((group, gi) => {
                    group.Data.forEach(async  (field, fi) => {
                        if(vm.contactId > 0){
                            if(field.name=='marital_status'){                              
                               vm.manageFieldHideShow(field.value);
                            }
                        }
                        if (field.name == 'email_id') {
                                field.validationRules.email=true;
                                field.config.options = null;
                            }
                            if(field.name == 'gender'){
                                field.value = 'Male'
                            }
                        field.config.onChange = vm.onChangeEventForFields;
                    })
                })
            })
        },
        manageFieldHideShow:function(val){  
            var vm=this;         
            vm.FormSchema.forEach((group, gi) => {                    
                group.Data.forEach(async (field, fi) => {   
                    if(field.name=='spouse_name' && val=="Single"){
                        field.visibility = false;
                    } 
                    else if(field.name=='spouse_name' && val=="Married"){
                        field.visibility = true;
                    }       
                })
            })
        },
        onChangeEventForFields: function (x, y, z) {
            var vm = this;
            if (y.name == "marital_status") {
                vm.FormSchema.forEach((group, gi) => {                    
                    group.Data.forEach(async (field, fi) => {   
                        if(field.name=='spouse_name' && y.value=="Single"){
                            field.visibility = false;
                        } 
                        else if(field.name=='spouse_name' && y.value=="Married"){
                            field.visibility = true;
                        }       
                    })
                })
            }
        },
        onSubmit(formfields, val) {          
            var vm = this;
            vm.$refs.form.validate().then((result) => {
                if(result){
                    var CustomFieldArray = vm.$refs.StageForm.ConvertDynamicFormObjToCustomFieldObj(vm.FormSchema);
                    CustomFieldArray.forEach((x) => {
                        if (x.field_name == 'created_by') {
                            x.field_value = vm.userId;
                        }
                        if (x.field_name == 'modified_by') {
                            x.field_value = vm.userId;
                        }
                        if (x.field_name == 'company_id') {
                            x.field_value = vm.companyId;
                        }    
                        if (x.field_name == 'contact_id') {
                            x.field_value = vm.contactId;
                        }                    
                    });
                    var postJSON = {
                        data: CustomFieldArray,                        
                    }
                    var objectPostString = JSON.stringify(postJSON);
                    ContactDataService.SaveContact(objectPostString).then(response => {
                        vm.isLoading=false;
                        if (response.data[0].Code == "1") {
                            if (vm.contactId > 0) {
                                vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Contact')]), "Success", true, vm.$t("Alert"));                                    
                            }
                            else {
                                vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Contact')]), "Success", true, vm.$t("Alert"));
                                                                     
                            }
                            vm.$router.push({ name:'ContactListing' });
                        }
                        else if (response.data[0].Code == "-1") {
                            vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('Contact')]), "warning", true, vm.$t("Alert"));                                
                        }
                        else {
                            vm.ShowAlert(vm.$t('AddedError', [vm.$t('Contact')]), "error", true, vm.$t("Alert"));                                 
                        }   
                    });
                }
            })
        }
    }
}
</script>